INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('6d5c6d78173a9d368d52ba93','venue','209','food','omer','omer','I ordered the hot Maine lobster roll from the stand outside of section 109 and was very disappointed. It was nearly $37 and was basically lobster pieces on a bun. They were even out of the bayside chips that were supposed to come with it. Skip this.','2026-07-09T15:03:57.224Z');
