INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('cf9bd0633ca396fe71a61fdd','venue','209','atmosphere','omer','omer','I went to a game with the two worst teams in the MLB and yet the vibes could not have been higher. There was an entire section doing "tarps off" where hundreds of guys took their shirts off and waved it. The colored light show in between innings had people on their feet and everyone was singing during karaoke and Take Me Out to the Ballgame. The game was one of the highest scoring of the season at 16-12 so we had lots of fireworks and cheering.','2026-07-09T15:03:57.224Z');
