INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1fc84572326d1ce2e9c97731','venue','209','tips','omer','omer','The 100s section lower rows have no shade from the sun so I would only recommend those during a night game or chillier days.','2026-07-09T15:03:57.224Z');
