INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('95aade8f210a2759e17d55bd','venue','209','atmosphere','robby','robby','The Mets and Royals aren''t the best MLB teams this year so I had low expectations but we ended up seeing one of the highest scoring games of the year. It felt like there was a homer every inning which made the game highly entertaining however I don''t think this is something you can count on.','2026-07-09T15:03:57.224Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('cd35e5d876228a07d9076e76','venue','209','tips','robby','robby','If you''re looking for consistency food wise, just hit the Shake Shack on the concourse behind the jumbotron.','2026-07-09T15:03:57.224Z');
