INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2470c2975d0fc8bb1395e4f9','venue','209','tips','robby','robby','Avoid cocktails. They''re all ridiculously priced throughout the stadium.','2026-07-09T15:03:57.224Z');
